import json
import re
import anthropic

client = anthropic.Anthropic()

# Define route handlers
def handle_billing(query: str) -> str:
    return client.messages.create(
        model="claude-haiku-4-5",
        max_tokens=512,
        system="You are a billing support specialist. Answer questions about invoices, payments, and subscriptions.",
        messages=[{"role": "user", "content": query}]
    ).content[0].text

def handle_technical(query: str) -> str:
    return client.messages.create(
        model="claude-sonnet-4-5",
        max_tokens=2048,
        system="You are a senior technical support engineer. Debug technical issues thoroughly.",
        messages=[{"role": "user", "content": query}]
    ).content[0].text

def handle_general(query: str) -> str:
    return client.messages.create(
        model="claude-haiku-4-5",
        max_tokens=512,
        system="You are a helpful customer support agent.",
        messages=[{"role": "user", "content": query}]
    ).content[0].text

# Rule-based fast paths
BILLING_KEYWORDS = re.compile(r"\b(invoice|payment|charge|subscription|billing|refund|cancel)\b", re.I)
TECH_KEYWORDS = re.compile(r"\b(error|bug|crash|not working|broken|exception|timeout|failed)\b", re.I)

def classify_with_llm(query: str) -> str:
    """LLM fallback classifier for ambiguous queries."""
    response = client.messages.create(
        model="claude-haiku-4-5",
        max_tokens=64,
        system="""Classify the user query into exactly one category:
- billing: payment, invoices, subscriptions, refunds
- technical: bugs, errors, troubleshooting
- general: everything else
Return JSON: {"category": "billing"|"technical"|"general", "confidence": 0.0-1.0}""",
        messages=[{"role": "user", "content": query}]
    )
    result = json.loads(response.content[0].text)
    return result["category"]

def route(query: str) -> str:
    """Hybrid router: rule-based fast path, LLM fallback."""
    # Fast path: deterministic rules
    if BILLING_KEYWORDS.search(query):
        return handle_billing(query)
    if TECH_KEYWORDS.search(query):
        return handle_technical(query)

    # LLM fallback for ambiguous queries
    category = classify_with_llm(query)
    handlers = {
        "billing": handle_billing,
        "technical": handle_technical,
        "general": handle_general,
    }
    return handlers.get(category, handle_general)(query)

# Test the router
test_queries = [
    "My invoice from last month shows a double charge.",
    "The API returns a 500 error when I call the /upload endpoint.",
    "What are your office hours?",
]
for q in test_queries:
    print(f"Q: {q}")
    print(f"A: {route(q)[:80]}...")
    print()
